    '{"name": "Oh,", "role": "colleague", "background": "Learn to prepare colleagues for challenges and normalize setbacks as part of the change process", "personality_traits": ["neutral"], "tone_spectrum": {"word_complexity": 0.3, "sentence_length": 0.3, "emotional_expressiveness": 0.2, "disclosure_level": 0.1, "response_latency": 0.3, "confidence_level": 0.2}, "starting_tone_position": 0.2, "triggers": ["direct criticism", "being told what to do", "lecturing", "judgment"], "comfort_topics": ["autonomy", "understanding", "being heard", "personal choice"]}'::jsonb,
    '{"start_node_id": "anti_1", "nodes": {"anti_1": {"id": "anti_1", "persona_text": "I''ve been walking regularly for a few weeks now and it''s going well. I feel good about it.", "persona_mood": "neutral_uncertain", "themes": ["Change"], "choice_points": [{"id": "cp_anti_1_0", "option_text": "That''s great! Just make sure you don''t stop now. You have to keep it up.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This creates pressure without actually preparing for challenges.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "anti_2a", "exploration_depth": "surface"}, {"id": "cp_anti_1_1", "option_text": "That''s really wonderful progress. As you continue, what situations might make it harder to keep walking?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect - affirms success and proactively prepares for challenges without being pessimistic.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "anti_2b", "exploration_depth": "surface"}, {"id": "cp_anti_1_2", "option_text": "Good, but the hard part is maintenance. Most people fail at this stage.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This emphasizes failure rather than building preparation skills.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "anti_2a", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "anti_2a": {"id": "anti_2a", "persona_text": "Oh, now I''m worried I''m going to fail too. Maybe I''m being too optimistic.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_anti_2a_0", "option_text": "I didn''t mean to worry you. Your success so far shows you''re capable. What I meant was, what challenges do you think might come up as you continue?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good recovery - affirms capability and reframes to constructive problem-solving.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "anti_2b", "exploration_depth": "surface"}, {"id": "cp_anti_2a_1", "option_text": "You should be worried. Maintenance is when most people slip up. You need to be realistic.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This reinforces discouragement rather than building coping skills.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "anti_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "anti_2b": {"id": "anti_2b", "persona_text": "Well, the weather is getting colder. And the holidays are coming up - I''ll be busier with family stuff. Those might make it harder.", "persona_mood": "neutral_uncertain", "themes": ["Relationships", "Barriers"], "choice_points": [{"id": "cp_anti_2b_0", "option_text": "You just can''t let those things be excuses. You need to prioritize your work performance.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This labels legitimate challenges as ''excuses'' rather than problem-solving.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "anti_2a", "exploration_depth": "surface"}, {"id": "cp_anti_2b_1", "option_text": "Cold weather and busy holidays - those are real challenges many people face. What has helped you in the past when the weather was bad or you had a busy schedule?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent - normalizes challenges and explores colleague''s existing coping resources.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "anti_3a", "exploration_depth": "surface"}, {"id": "cp_anti_2b_2", "option_text": "Don''t let cold weather stop you. Just dress in layers and use willpower.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This minimizes the challenge without collaboratively problem-solving.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "anti_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "anti_3a": {"id": "anti_3a", "persona_text": "In the past when it was cold, I used to walk in the mall sometimes. And when I''m busy... honestly, I haven''t figured that one out yet. I just let exercise slide.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_anti_3a_0", "option_text": "Mall walking is a great strategy you''ve used before. For busy times, if you find yourself with a packed schedule, what could you do to keep some movement in your day, even if it''s not a full walk?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect - reinforces existing coping and creates implementation intention for the gap.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "anti_4a", "exploration_depth": "surface"}, {"id": "cp_anti_3a_1", "option_text": "You can''t let a busy schedule be an excuse. You have to make time no matter what.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This creates pressure and doesn''t acknowledge that flexibility might be needed.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "anti_2a", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "anti_4a": {"id": "anti_4a", "persona_text": "Maybe I could do shorter walks? Like even just 10 minutes, a couple times when I have a break? Something is better than nothing, right?", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_anti_4a_0", "option_text": "You''re creating a flexible backup plan - if a full walk isn''t possible, then doing shorter walks when you can. That''s smart thinking. How would you feel about yourself if you did miss a day or two?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Excellent - reinforces the adaptive plan and proactively addresses potential self-judgment.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "anti_5a", "exploration_depth": "surface"}, {"id": "cp_anti_4a_1", "option_text": "10 minutes isn''t really enough to make a difference. You should stick to the 30-minute walks every time.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This dismisses the colleague''s realistic backup plan and creates all-or-nothing thinking.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "anti_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "anti_5a": {"id": "anti_5a", "persona_text": "Honestly? I''d probably feel like I failed. That I''m not disciplined enough.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [{"id": "cp_anti_5a_0", "option_text": "If you miss a day, you''ve failed. That''s just the reality of making changes.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This reinforces unhelpful all-or-nothing thinking about setbacks.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "anti_end_poor", "exploration_depth": "surface"}, {"id": "cp_anti_5a_1", "option_text": "Setbacks are a common part of change, not failure. Missing a day doesn''t erase all the walking you''ve done. What would you want to tell a friend who missed a day of their walking plan?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect - normalizes setbacks and uses perspective to challenge self-judgment.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "anti_6a", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "anti_6a": {"id": "anti_6a", "persona_text": "I''d tell them it''s okay, that they should just start again the next day. I guess I''m harder on myself than I''d be on someone else.", "persona_mood": "neutral_uncertain", "themes": ["Barriers"], "choice_points": [{"id": "cp_anti_6a_0", "option_text": "You''d be compassionate with a friend. What would it be like to extend that same kindness to yourself if you miss a day?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Good - highlights the insight and invites applying it to self.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "anti_7a", "exploration_depth": "surface"}, {"id": "cp_anti_6a_1", "option_text": "Well, you should be hard on yourself. That''s what creates accountability.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This contradicts the helpful insight the colleague just had.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "anti_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "anti_7a": {"id": "anti_7a", "persona_text": "That would be... different. I think it would help me get back on track faster instead of spiraling into feeling bad about myself.", "persona_mood": "neutral_uncertain", "themes": ["Change"], "choice_points": [{"id": "cp_anti_7a_0", "option_text": "So if you do miss a day or two during the holidays, what might help you get back to walking?", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "Perfect - creates a specific plan for recovery from setback.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "anti_end_good", "exploration_depth": "surface"}, {"id": "cp_anti_7a_1", "option_text": "Good, but try not to miss any days. Just stay disciplined.", "preview_hint": "MI-consistent approach", "rapport_impact": 0, "resistance_impact": 0, "tone_shift": 0.0, "technique_tags": ["unknown"], "competency_links": [], "feedback": {"immediate": "This undoes the helpful work on normalizing and planning for setbacks.", "learning_note": "Continue practicing MI techniques to build your therapeutic skills."}, "next_node_id": "anti_end_poor", "exploration_depth": "surface"}], "is_endpoint": false, "endpoint_type": null}, "anti_end_good": {"id": "anti_end_good", "persona_text": "I think reminding myself that I''ve built this habit - I can get back to it. Maybe looking at my walking log to see all the days I did walk. And then just going for a short walk to restart, not waiting until I can do the ''full'' walk. Just getting back into motion.", "persona_mood": "neutral_uncertain", "themes": ["Identity"], "choice_points": [], "is_endpoint": true, "endpoint_type": "successful_engagement"}, "anti_end_poor": {"id": "anti_end_poor", "persona_text": "I feel like if I slip up even once, I''ll have failed. This all feels like a lot of pressure now.", "persona_mood": "neutral_uncertain", "themes": ["General"], "choice_points": [], "is_endpoint": true, "endpoint_type": "failed_engagement"}}}'::jsonb,
